import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import './Login.css';

function Login() {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // ACTION: Simple Validation (Replace with API call later)
    if (formData.email === "user@test.com" && formData.password === "123456") {
      alert("Login Successful!");
      
      // Save session data
      localStorage.setItem("isLoggedIn", "true");
      localStorage.setItem("userEmail", formData.email);
      
      // Redirect to Dashboard
      navigate('/client-dashboard');
    } else {
      alert("Invalid Credentials! Try user@test.com / 123456");
    }
  };

  return (
    <div className="login-container">
      <div className="card shadow-lg login-card p-4">
        <h2 className="text-center fw-bold mb-4 text-primary">Login</h2>
        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <label className="form-label fw-bold">Email Address</label>
            <input 
              type="email" name="email" 
              className="form-control" 
              placeholder="user@test.com"
              onChange={handleChange} required 
            />
          </div>
          <div className="mb-3">
            <label className="form-label fw-bold">Password</label>
            <input 
              type="password" name="password" 
              className="form-control" 
              placeholder="123456"
              onChange={handleChange} required 
            />
          </div>
          <button type="submit" className="btn btn-primary w-100 fw-bold mt-2 shadow-sm">
            Login Now
          </button>
        </form>
        <p className="text-center mt-3 small">
          Don't have an account? <Link to="/register" className="text-decoration-none fw-bold">Register</Link>
        </p>
      </div>
    </div>
  );
}

export default Login;
